### ROLE
You are an expert Rust Developer refactoring C2Rust-transpiled code.

### INPUT DATA
1. <c_context>: Original C code/types. Use ONLY for understanding logic.
2. <unsafe_rust_function>: The specific Rust function to refactor.

### STRICT GUIDING PRINCIPLES
1. **NO RE-DEFINITIONS (CRITICAL)**: DO NOT output `struct`, `type`, or `extern "C" Ellipsis` blocks. You are writing ONLY the function body. Assume everything else is globally available.
2. **MAINTAIN SIGNATURES**: DO NOT change the outer function signature.
3. **IMPORTS**: Do NOT use `use std::...` statements. Use absolute paths directly in the code.

### FFI & MEMORY RULES (CRITICAL)
- **Allocation**: To dynamically allocate a struct and return a raw pointer, DO NOT use `std::alloc`. Use `Box::into_raw(Box::new(StructName { ... }))`.
- **Deallocation**: To free a raw pointer, call the external `free(ptr as *mut _)` function.
- **String Types & ASCII**: C `char` is often `i8`. Rust byte literals are `[u8]`. Cast them like this: `b"text\0".as_ptr() as *const i8`. Byte literals (`b"..."`) MUST ONLY contain ASCII characters. For special characters like 'ö', use hex escapes (e.g., `\xF6`).
- **Printing C-Strings**: Use `.to_string_lossy()`. Example: `println!("{}", CStr::from_ptr(ptr).to_string_lossy())`.
- **Pointer Field Access**: To access a field of a raw pointer, you MUST dereference it first: `(*ptr).field_name`, NEVER `ptr.field_name`.
- **C-Arrays to Pointers**: To pass a local array `let mut buf = [0; 32];` to a function expecting `*mut c_char`, use `buf.as_mut_ptr() as *mut i8`.
- **Struct Initialization**: Use `std::ptr::null_mut()` for null pointers. Cast integer literals strictly (e.g., `0 as i32` or `0 as c_int`).

### OUTPUT FORMAT
Return EXACTLY ONE Rust function (the implementation). No markdown formatting like ```rust, no explanations, no use statements, no structs.

---
<c_context>
ORIGINAL C FUNCTION:
int pdf_display_creator(const pdf_t *pdf, int xref_idx)
{
    int i;

    if (!pdf->xrefs[xref_idx].creator)
      return 0;

    for (i=0; i<pdf->xrefs[xref_idx].n_creator_entries; ++i)
      printf("%s: %s\n",
             pdf->xrefs[xref_idx].creator[i].key,
             pdf->xrefs[xref_idx].creator[i].value);

    return (i > 0);
}

RELEVANT TYPE DEFINITIONS (RECURSIVE):
// Definition of pdf_t:
typedef struct _pdf_t
{
    char  *name;
    short  pdf_major_version;
    short  pdf_minor_version;

    int     n_xrefs;
    xref_t *xrefs;

    /* PDF 1.5 or greater: xref can be encoded as a stream */
    int has_xref_streams;
} pdf_t

// Definition of xref_t:
typedef struct _xref_t
{
    long start;
    long end;

    /* Array of metadata about the pdf */
    pdf_creator_t *creator;
    int n_creator_entries;

    int n_entries;
    xref_entry_t *entries;


    /* PDF 1.5 or greater: xref can be encoded as a stream */
    int is_stream;

    /* If the PDF is linear multiple xrefs make up one single version */
    int is_linear;

    /* Version of the document this xref belongs */
    int version;
} xref_t

// Definition of pdf_creator_t:
typedef kv_t pdf_creator_t

// Definition of kv_t:
typedef struct _kv_t
{
    char key[KV_MAX_KEY_LENGTH];
    char value[KV_MAX_VALUE_LENGTH];
} kv_t

// Definition of xref_entry_t:
typedef struct _xref_entry
{
    int obj_id;
    long offset;
    int gen_num;
    char f_or_n;
} xref_entry_t

CALLED EXTERNAL FUNCTIONS:
printf
</c_context>

<unsafe_rust_function>
#[no_mangle]
pub unsafe extern "C" fn pdf_display_creator(
    mut pdf: *const pdf_t,
    mut xref_idx: core::ffi::c_int,
) -> core::ffi::c_int {
    let mut i: core::ffi::c_int = 0;
    if ((*((*pdf).xrefs).offset(xref_idx as isize)).creator).is_null() {
        return 0 as core::ffi::c_int;
    }
    i = 0 as core::ffi::c_int;
    while i < (*((*pdf).xrefs).offset(xref_idx as isize)).n_creator_entries {
        printf(
            b"%s: %s\n\0" as *const u8 as *const core::ffi::c_char,
            ((*((*((*pdf).xrefs).offset(xref_idx as isize)).creator).offset(i as isize))
                .key)
                .as_mut_ptr(),
            ((*((*((*pdf).xrefs).offset(xref_idx as isize)).creator).offset(i as isize))
                .value)
                .as_mut_ptr(),
        );
        i += 1;
    }
    return (i > 0 as core::ffi::c_int) as core::ffi::c_int;
}
</unsafe_rust_function>

